import Post from './component/Post';
import React,{useState} from 'react';
import './App.css';

let posts = [{ title: "new post!", info: "hey" }, { title: "new cat", info: "i got a new cat and calles him Boris" }, { title: "its my brithday", info: "celebratin with friends today at 10 pm " }, { title: "won in a game", info: "Bal bla bla bla " }]

function App() {





  return (
    <div className="App">
      <div className="App">
        {posts.map((item) => {
          return <Post title={item.title} info={item.info} />
        })}
      </div>
    </div>
  );
}

export default App;
